SET NAMES utf8mb4;

INSERT INTO actas (titulo, data, contido, estado, creado) VALUES (
'Acta Asamblea Extraordinaria - Renovación Xunta Directiva',
'2026-01-31',
'ACTA ASAMBLEA EXTRAORDINARIA ASOCIACIÓN LEVADA ARRAIANA\n\nAsunto: Xunta Extraordinaria para a renovación anual da Xunta Directiva da Asociación.\n\nLugar: Local Social, baixo do Centro Cultural La Social de Estás, Tomiño.\n\nData: 31/01/2026.\n\nHora inicio: 11:00 horas.\n\nAsistentes:\nMaría Pérez\nMónica\nLeticia\nMaruxa\nJavier\nVíctor\nJosé\nÁlvaro\nAlba\nÁlex\nElena\nGabri\n\nOrde do día:\n1- Renovación anual da Xunta Directiva.\n\nDesenvolvemento:\n\nAcórdase por unanimidade de todos os presentes a renovación da Xunta Directiva da Asociación.\n\nQueda conformada a nova xunta directiva:\n- Presidente: José\n- Vicepresidente: Víctor\n- Secretaria: Maruxa\n- Tesoureira: Leticia\n\nSen máis asuntos que tratar, levántase a sesión ás 11:30 horas.\n\nAsdo:\nJosé (Presidente)\nMaruxa (Secretaria)',
'Publicada',
NOW()
);

INSERT INTO actas (titulo, data, contido, estado, creado) VALUES (
'Acta Reunión Ordinaria - Funcionamento interno',
'2025-11-17',
'ACTA LEVADA ARRAIANA\n\nLugar: Centro cultural de Estás (Tomiño)\nData: 17 novembro 2025\nHora de inicio: 19:30\n\nAsistentes:\nMónica\nLeti\nMaruxa\nXurxo\nJavi\nVíctor\nJose\nÁlvaro\nAlba\nÁlex\nElena\nGabri\n\nOrde do día:\n1- Baixa de Mónica como tesoureira. Reasignación do posto de tesoureiro.\n2- Funcionamento interno.\n\nDesenvolvemento:\n\n1- BAIXA DE MÓNICA COMO TESOUREIRA\n\nMónica presenta a súa baixa como tesoureira por motivos persoais. Acórdase por unanimidade que Leticia asuma o cargo de tesoureira a partir desta data.\n\n2- FUNCIONAMENTO INTERNO\n\nDebátense varios aspectos do funcionamento interno da asociación:\n\n2.1- Grupos de traballo:\nAcórdase crear os seguintes grupos:\n- Grupo de comunicación e redes sociais: Alba e Elena\n- Grupo de eventos: Javi e Víctor\n- Grupo de material e equipamento: Álvaro e Álex\n- Grupo de repertorio musical: Xurxo e Gabri\n\n2.2- Cotas:\nAcórdase manter a cota mensual de 15 euros por socio. O pago realizarase por transferencia bancaria antes do día 5 de cada mes.\n\n2.3- Ensaios:\nEstablécese o horario de ensaios:\n- Mércores de 20:00 a 22:00 (ensaio regular)\n- Sábados de 11:00 a 13:00 (ensaio extra antes de eventos)\n\n2.4- Material:\nÁlvaro e Álex farán un inventario completo do material da asociación antes do 15 de decembro.\n\n2.5- Próximos eventos:\n- Cabalgata de Reis (05/01/2026): confirmada a participación\n- Entroido de Tomiño (febreiro 2026): pendente de confirmar datas co Concello\n\nSen máis asuntos que tratar, levántase a sesión ás 21:15 horas.\n\nAsdo:\nJose (Presidente en funcións)\nMaruxa (Secretaria)',
'Publicada',
NOW()
);
